DROP TABLE IF EXISTS public.hijri_date_mapping;

CREATE TABLE public.hijri_date_mapping (
  gregorian_date    date    NULL,
  hijri_date_day    integer NOT NULL,
  hijri_date_month  integer NOT NULL,
  hijri_date_year   integer NOT NULL,
  remark            text    NULL,
  CONSTRAINT hijri_date_mapping_pkey
    PRIMARY KEY (hijri_date_day, hijri_date_month, hijri_date_year),
  CONSTRAINT hijri_date_mapping_hijri_date_month_fkey
    FOREIGN KEY (hijri_date_month)
    REFERENCES hijri_month (hijri_date_month)
) TABLESPACE pg_default;


DROP TABLE IF EXISTS public.hijri_dates;

-- Recreate table
CREATE TABLE public.hijri_dates (
  created_at        timestamptz NOT NULL DEFAULT now(),
  updated_at        timestamptz NOT NULL DEFAULT now(),
  gregorian_date    date        NOT NULL,
  special_date_en   varchar(500),
  hijri_date_day    integer     NOT NULL,
  hijri_date_month  integer     NOT NULL,
  hijri_date_year   integer     NOT NULL,
  hijri_date        varchar,
  id                bigint GENERATED BY DEFAULT AS IDENTITY NOT NULL,
  special_date_no   varchar,
  special_date_ar   varchar,
  CONSTRAINT hijri_dates_pkey PRIMARY KEY (hijri_date_day, hijri_date_month, hijri_date_year),
  CONSTRAINT hijri_dates_hijri_date_month_fkey
    FOREIGN KEY (hijri_date_month) REFERENCES public.hijri_month (hijri_date_month)
);

-- 1. Drop trigger if exists
DROP TRIGGER IF EXISTS update_hijri_dates_updated_at ON public.hijri_dates;

-- 2. Drop function if exists  
DROP FUNCTION IF EXISTS update_updated_at_column();

-- 3. Create reusable function
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- 4. Create trigger
CREATE TRIGGER update_hijri_dates_updated_at
  BEFORE UPDATE ON public.hijri_dates
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();


