  shadow_1x time without time zone null,
  shadow_2x time without time zone null,
  wusta_noon_sunset time without time zone null,
  maghrib time without time zone null,
  isha time without time zone null,
  istiwa_noon time without time zone null,
  muntasafallayl_midnight time without time zone null,
  ghrub_sunset time without time zone null,
  shuruq_sunrise time without time zone null,
  laylat_falakia_two3rd time without time zone null,
  laylatal_shariea_two3rd time without time zone null,
  laylat_falakia_one3rd time without time zone null,
  laylatal_shariea_one3rd time without time zone null,
  fajr_endtime time without time zone null,
  shafaqal_ahmar_end_redlight time without time zone null,
  shafaqal_abyadh_end_whitelight time without time zone null,
  date date not null,
  asr time without time zone null,
  fajr_sadiq time without time zone null,
  prayer_after_sunrise time without time zone null,
  asr_endtime time without time zone null,
  altitude_midnight time without time zone null,
  altitude_noon time without time zone null,
  sun_shadow_noon numeric(9, 6) null,
  sun_shadow_wusta numeric(9, 6) null,
  elevation_asrwusta numeric(9, 6) null,
  elevation_midnight numeric(9, 6) null,
  elevation_noon numeric(9, 6) null,
  elevation_shadow_1x numeric(9, 6) null,
  elevation_shadow_2x numeric(9, 6) null,
  location_iso text not null,
  kommune text null,
  prayer_method integer not null,
  constraint prayertime_pkey primary key (date, location_iso, prayer_method),
  constraint prayertime_location_iso_fkey foreign KEY (location_iso) references location_t (location_iso)
) TABLESPACE pg_default;


